qry:select.qry:xquery:
		for $r in sql('

		SELECT
			EMP.c_empresa,
			EMP.d_empresa,
			CAR.c_carpeta,
			CAR.d_carpeta,
			ADE.oi_adelanto,
			SUJ.c_sujeto,
			SUJ.d_sujeto,
			SUC.c_ubicacion,
			SUC.d_ubicacion,
			REN.oi_rendicion,
			REN.f_rendicion,
			REN.n_monto_rendicion,
			REN.l_anulado,
			CMP.f_comprobante,
			CMP.d_razon_social,
			TC.c_tipo_comprob,
			TC.d_tipo_comprob,
			CMP.c_nro_comp,
			CMP.n_subtotal,
			CMP.n_iva,
			CMP.n_otros_impuestos,
			CMP.n_total,
			CMP.f_transferido					

		FROM				
			LEG06_COMPS_RENDICION as CMP,
			LEG06_RENDICIONES as REN,
			LEG04_ADELANTOS as ADE,
			LEG01_CARPETAS as CAR,
			ORG03_EMPRESAS as EMP,
			LEG40_CLASIF_SUJ as CS,
     	LEG40_SUJETOS as SUJ,
     	ORG03_UBICACIONES as SUC,
     	LEG63_TIPOS_COMPROB as TC				

		JOIN
			CMP.oi_rendicion INNER REN.oi_rendicion,
			REN.oi_adelanto INNER ADE.oi_adelanto,
			ADE.oi_carpeta INNER CAR.oi_carpeta,
			CAR.oi_empresa INNER EMP.oi_empresa,
			ADE.oi_clasif_sujeto INNER CS.oi_clasif_sujeto,
			CS.oi_sujeto INNER SUJ.oi_sujeto,
			ADE.oi_ubicacion INNER SUC.oi_ubicacion,
			CMP.oi_tipo_comprob INNER TC.oi_tipo_comprob											

		WHERE
			1=1
			{%? (#FILTRO:@oi_empresa!='')
				{% AND CAR.oi_empresa = {#FILTRO:@oi_empresa} %}
				{% %}
			%}
			{%? (#FILTRO:@oi_carpeta!='')
				{% AND ADE.oi_carpeta = {#FILTRO:@oi_carpeta} %}
				{% %}
			%}
			{%? (#FILTRO:@oi_adelanto!='')
				{% AND REN.oi_adelanto = {#FILTRO:@oi_adelanto} %}
				{% %}
			%}
			{%? (#FILTRO:@l_rend_anuladas!='1')
				{% AND REN.l_anulado = 0 %}
				{% %}
			%}
			{%? (#FILTRO:@f_rend_desde!='')
				{% AND REN.f_rendicion >= {#FILTRO:@f_rend_desde} %}
				{% %}
			%}
			{%? (#FILTRO:@f_rend_hasta!='')
				{% AND REN.f_rendicion <= ADDDAYS({#FILTRO:@f_rend_hasta},1) %}
				{% %}
			%}					
			{%? (#FILTRO:@l_no_transf_gp='1')
				{% AND ISNULL(CMP.f_transferido) %}
				{% %}
			%}					
			{%? (#FILTRO:@f_transf_gp_desde!='')
				{% AND CMP.f_transferido >= {#FILTRO:@f_transf_gp_desde} %}
				{% %}
			%}
			{%? (#FILTRO:@f_transf_gp_hasta!='')
				{% AND CMP.f_transferido <= ADDDAYS({#FILTRO:@f_transf_gp_hasta},1) %}
				{% %}
			%}

		ORDER BY
			c_empresa ASC,
			c_carpeta ASC,
			oi_adelanto ASC,
			oi_rendicion ASC

	')/ROWS/ROW
